import time
from node import Node
from message_queue import MessageQueue

def process_messages(nodes, message_queue):
    while message_queue.has_messages():
        sender, message = message_queue.dequeue()
        for node in nodes:
            if node.id != sender:
                node.whenReceiving(message)

def all_nodes_finished(nodes):
    return all(node.state == "finished" for node in nodes)

def simulate_tendermint(nodes_n, max_iterations=10):
    message_queue = MessageQueue()
    nodes = [Node(i, message_queue) for i in range(nodes_n)]
    for node in nodes:
        node.whenStarting()

    current_iteration = 0
    while not all_nodes_finished(nodes) and current_iteration < max_iterations:
        # Process messages from the message queue
        process_messages(nodes, message_queue)

        # Handle timeouts
        # This can be replaced with more realistic approaches, such as trigger-based timeouts.
        for node in nodes:
            node.whenTimeout()

        current_iteration += 1

if __name__ == "__main__":
    simulate_tendermint(4)
```

In this example, I added a `max_iterations` parameter to limit the number of iterations for the simulation to prevent infinite loops, which can be adjusted according to your needs. The simulation now continues until all nodes finish the consensus process or until the maximum number of iterations is reached.

